package org.example.aop.annotator
import com.intellij.lang.annotation.AnnotationHolder import com.intellij.lang.annotation.Annotator import com.intellij.lang.annotation.HighlightSeverity import com.intellij.psi.PsiAnnotation import com.intellij.psi.PsiElement
class AopAnnotator : Annotator {
private val AOP_SHORT_NAMES = setOf( "Aspect", "Before", "After", "Around", "AfterReturning", "AfterThrowing", "Pointcut" )
private val AOP_PACKAGE = "org.aspectj.lang.annotation"
override fun annotate(element: PsiElement, holder: AnnotationHolder) { if (element !is PsiAnnotation) return
val nameRef = element.nameReferenceElement ?: return if (nameRef.referenceName !in AOP_SHORT_NAMES) return
val qualifiedName = element.qualifiedName ?: return if (!qualifiedName.startsWith(AOP_PACKAGE)) return
holder.newSilentAnnotation(HighlightSeverity.INFORMATION) .range(nameRef) .textAttributes(AopTextAttributes.AOP_ANNOTATION) .create() } }

package org.example.aop.completion

import com.intellij.codeInsight.completion.*
import com.intellij.codeInsight.lookup.LookupElementBuilder
import com.intellij.patterns.PlatformPatterns
import com.intellij.psi.*
import com.intellij.psi.util.PsiTreeUtil
import com.intellij.util.ProcessingContext

class AopCompletionContributor : CompletionContributor() {

    init {
        extend(
            CompletionType.BASIC,
            PlatformPatterns.psiElement(PsiJavaToken::class.java)
                .withParent(PsiLiteralExpression::class.java),
            AopPointcutCompletionProvider()
        )
    }
}

private class AopPointcutCompletionProvider : CompletionProvider<CompletionParameters>() {

    companion object {
        private val AOP_ANNOTATIONS = setOf(
            "org.aspectj.lang.annotation.Before",
            "org.aspectj.lang.annotation.After",
            "org.aspectj.lang.annotation.Around",
            "org.aspectj.lang.annotation.AfterReturning",
            "org.aspectj.lang.annotation.AfterThrowing",
            "org.aspectj.lang.annotation.Pointcut"
        )

        private val DESIGNATORS = listOf(
            "execution"     to "execution(modifiers? return-type declaring-type? method-name(params) throws?)",
            "within"        to "within(type-pattern)",
            "@annotation"   to "@annotation(annotation-type)",
            "@within"       to "@within(annotation-type)",
            "this"          to "this(type)",
            "target"        to "target(type)",
            "args"          to "args(param-types)",
            "@args"         to "@args(annotation-types)",
            "@target"       to "@target(annotation-type)",
            "bean"          to "bean(name-or-pattern)"
        )
    }

    override fun addCompletions(
        parameters: CompletionParameters,
        context: ProcessingContext,
        result: CompletionResultSet
    ) {
        val position = parameters.position
        val annotation = PsiTreeUtil.getParentOfType(position, PsiAnnotation::class.java) ?: return
        if (annotation.qualifiedName !in AOP_ANNOTATIONS) return

        // Extract the typed prefix from inside the string literal
        val rawText = position.text
        val quoteIdx = rawText.indexOf('"')
        val dummyIdx = rawText.indexOf(CompletionUtilCore.DUMMY_IDENTIFIER_TRIMMED)
        val prefix = when {
            quoteIdx >= 0 && dummyIdx > quoteIdx -> rawText.substring(quoteIdx + 1, dummyIdx)
            dummyIdx >= 0 -> rawText.substring(0, dummyIdx)
            else -> ""
        }

        val prefixedResult = result.withPrefixMatcher(prefix)

        DESIGNATORS.forEach { (designator, description) ->
            prefixedResult.addElement(
                LookupElementBuilder.create(designator)
                    .withPresentableText("$designator(...)")
                    .withTailText("  $description", true)
                    .withTypeText("pointcut designator")
                    .bold()
                    .withInsertHandler { ctx, _ ->
                        ctx.document.insertString(ctx.tailOffset, "()")
                        ctx.editor.caretModel.moveToOffset(ctx.tailOffset - 1)
                    }
            )
        }
    }
}

package org.example.aop.completion

import com.intellij.codeInsight.completion.*
import com.intellij.codeInsight.lookup.LookupElementBuilder
import com.intellij.patterns.PlatformPatterns
import com.intellij.psi.*
import com.intellij.psi.util.PsiTreeUtil
import com.intellij.util.ProcessingContext
import org.example.aop.inspection.AopInspectionRules

class AopCompletionContributor : CompletionContributor() {

    init {
        extend(
            CompletionType.BASIC,
            PlatformPatterns.psiElement(PsiJavaToken::class.java)
                .withParent(PsiLiteralExpression::class.java),
            AopPointcutCompletionProvider()
        )
    }
}

private class AopPointcutCompletionProvider : CompletionProvider<CompletionParameters>() {

    override fun addCompletions(
        parameters: CompletionParameters,
        context: ProcessingContext,
        result: CompletionResultSet
    ) {
        val position = parameters.position
        val annotation = PsiTreeUtil.getParentOfType(position, PsiAnnotation::class.java) ?: return
        if (!AopCompletionContext.isSupportedAopAdviceAnnotation(annotation.qualifiedName)) return

        val nameValuePair = PsiTreeUtil.getParentOfType(position, PsiNameValuePair::class.java)
        if (!AopCompletionContext.isSupportedPointcutAttribute(nameValuePair?.name)) return

        // Extract the typed prefix from inside the string literal
        val prefix = AopCompletionContext.extractPrefix(position.text)

        val prefixedResult = result.withPrefixMatcher(prefix)

        AopInspectionRules.pointcutCompletionItems.forEach { (designator, description) ->
            prefixedResult.addElement(
                LookupElementBuilder.create(designator)
                    .withPresentableText("$designator(...)")
                    .withTailText("  $description", true)
                    .withTypeText("pointcut designator")
                    .bold()
                    .withInsertHandler { ctx, _ ->
                        ctx.document.insertString(ctx.tailOffset, "()")
                        ctx.editor.caretModel.moveToOffset(ctx.tailOffset - 1)
                    }
            )
        }
    }
}

internal object AopCompletionContext {
    private val supportedPointcutAttributeNames = setOf(
        PsiAnnotation.DEFAULT_REFERENCED_METHOD_NAME,
        "value",
        "pointcut"
    )

    fun isSupportedAopAdviceAnnotation(qualifiedName: String?): Boolean {
        return qualifiedName in AopInspectionRules.adviceAndPointcutAnnotations
    }

    fun isSupportedPointcutAttribute(attributeName: String?): Boolean {
        return attributeName == null || attributeName in supportedPointcutAttributeNames
    }

    fun extractPrefix(rawTokenText: String): String {
        val quoteIdx = rawTokenText.indexOf('"')
        val dummyIdx = rawTokenText.indexOf(CompletionUtilCore.DUMMY_IDENTIFIER_TRIMMED)
        return when {
            quoteIdx >= 0 && dummyIdx > quoteIdx -> rawTokenText.substring(quoteIdx + 1, dummyIdx)
            dummyIdx >= 0 -> rawTokenText.substring(0, dummyIdx)
            else -> ""
        }
    }
}

package org.example.aop.inspection

import com.intellij.psi.PsiAnnotation
import com.intellij.psi.PsiClass

object AopInspectionRules {
    const val AOP_ANNOTATION_PACKAGE = "org.aspectj.lang.annotation"
    const val ASPECT_ANNOTATION = "org.aspectj.lang.annotation.Aspect"

    val adviceAndPointcutAnnotations = setOf(
        "org.aspectj.lang.annotation.Before",
        "org.aspectj.lang.annotation.After",
        "org.aspectj.lang.annotation.Around",
        "org.aspectj.lang.annotation.AfterReturning",
        "org.aspectj.lang.annotation.AfterThrowing",
        "org.aspectj.lang.annotation.Pointcut"
    )

    val aopAnnotationQualifiedNames = setOf(ASPECT_ANNOTATION) + adviceAndPointcutAnnotations

    val aopAnnotationShortNames = aopAnnotationQualifiedNames
        .map { it.substringAfterLast('.') }
        .toSet()

    val springBeanAnnotations = setOf(
        "org.springframework.stereotype.Component",
        "org.springframework.stereotype.Service",
        "org.springframework.stereotype.Repository",
        "org.springframework.stereotype.Controller",
        "org.springframework.web.bind.annotation.RestController",
        "org.springframework.context.annotation.Configuration",
        "org.springframework.web.bind.annotation.ControllerAdvice",
        "org.springframework.web.bind.annotation.RestControllerAdvice"
    )

    val supportedPointcutDesignators = setOf(
        "execution", "within", "this", "target", "args",
        "@target", "@within", "@annotation", "@args", "bean",
        "cflow", "cflowbelow", "initialization", "preinitialization",
        "staticinitialization", "handler", "adviceexecution"
    )

    val pointcutCompletionItems = listOf(
        "execution" to "execution(modifiers? return-type declaring-type? method-name(params) throws?)",
        "within" to "within(type-pattern)",
        "@annotation" to "@annotation(annotation-type)",
        "@within" to "@within(annotation-type)",
        "this" to "this(type)",
        "target" to "target(type)",
        "args" to "args(param-types)",
        "@args" to "@args(annotation-types)",
        "@target" to "@target(annotation-type)",
        "bean" to "bean(name-or-pattern)"
    )

    private val functionLikeTokenPattern = Regex("([@]?[A-Za-z_][A-Za-z0-9_.]*)\\s*\\(")
    private val trailingOperatorPattern = Regex("(&&|\\|\\|)$")
    private val consecutiveOperatorPattern = Regex("(&&|\\|\\|)\\s*(&&|\\|\\|)")
    private val missingOperatorBetweenClausesPattern = Regex("\\)\\s*(!?[@A-Za-z_])")

    data class PointcutValidationError(
        val kind: PointcutValidationErrorKind,
        val message: String
    )

    enum class PointcutValidationErrorKind {
        EMPTY_EXPRESSION,
        EMPTY_NEGATION,
        UNBALANCED_PARENTHESES,
        LEADING_OPERATOR,
        TRAILING_OPERATOR,
        CONSECUTIVE_LOGICAL_OPERATORS,
        MISSING_OPERATOR_BETWEEN_CLAUSES,
        UNKNOWN_DESIGNATOR,
    }

    fun hasSpringBeanAnnotation(annotations: Set<String>): Boolean {
        return annotations.any { it in springBeanAnnotations }
    }

    fun isSpringBeanClass(psiClass: PsiClass): Boolean {
        val annotations = psiClass.modifierList?.annotations.orEmpty()
        val visited = mutableSetOf<String>()
        return annotations.any { isSpringBeanAnnotation(it, visited) }
    }

    fun validatePointcutExpression(rawExpression: String): String? {
        return validatePointcutExpressionDetailed(rawExpression)?.message
    }

    fun validatePointcutExpressionDetailed(rawExpression: String): PointcutValidationError? {
        val expression = rawExpression.trim()

        if (expression.isEmpty()) {
            return PointcutValidationError(
                PointcutValidationErrorKind.EMPTY_EXPRESSION,
                "Pointcut expression cannot be empty"
            )
        }

        if (expression.all { it == '!' }) {
            return PointcutValidationError(
                PointcutValidationErrorKind.EMPTY_NEGATION,
                "Pointcut expression cannot contain only negation operator(s)"
            )
        }

        if (!hasBalancedParentheses(expression)) {
            return PointcutValidationError(
                PointcutValidationErrorKind.UNBALANCED_PARENTHESES,
                "Pointcut expression has unbalanced parentheses"
            )
        }

        if (expression.startsWith("&&") || expression.startsWith("||")) {
            return PointcutValidationError(
                PointcutValidationErrorKind.LEADING_OPERATOR,
                "Pointcut expression cannot start with a logical operator"
            )
        }

        if (trailingOperatorPattern.containsMatchIn(expression)) {
            return PointcutValidationError(
                PointcutValidationErrorKind.TRAILING_OPERATOR,
                "Pointcut expression cannot end with a logical operator"
            )
        }

        if (consecutiveOperatorPattern.containsMatchIn(expression)) {
            return PointcutValidationError(
                PointcutValidationErrorKind.CONSECUTIVE_LOGICAL_OPERATORS,
                "Pointcut expression has consecutive logical operators"
            )
        }

        if (missingOperatorBetweenClausesPattern.containsMatchIn(expression)) {
            return PointcutValidationError(
                PointcutValidationErrorKind.MISSING_OPERATOR_BETWEEN_CLAUSES,
                "Pointcut expression is missing a logical operator between clauses"
            )
        }

        val functionLikeTokens = functionLikeTokenPattern.findAll(expression).map { it.groupValues[1] }
        for (token in functionLikeTokens) {
            if ('.' !in token && token !in supportedPointcutDesignators) {
                return PointcutValidationError(
                    PointcutValidationErrorKind.UNKNOWN_DESIGNATOR,
                    "Unknown pointcut designator: '$token'"
                )
            }
        }

        return null
    }

    private fun isSpringBeanAnnotation(annotation: PsiAnnotation, visited: MutableSet<String>): Boolean {
        val qualifiedName = annotation.qualifiedName ?: return false
        if (qualifiedName in springBeanAnnotations) return true
        if (!visited.add(qualifiedName)) return false

        val annotationClass = annotation.nameReferenceElement?.resolve() as? PsiClass ?: return false
        return annotationClass.modifierList
            ?.annotations
            .orEmpty()
            .any { isSpringBeanAnnotation(it, visited) }
    }

    private fun hasBalancedParentheses(expr: String): Boolean {
        var depth = 0
        for (ch in expr) {
            when (ch) {
                '(' -> depth++
                ')' -> if (--depth < 0) return false
            }
        }
        return depth == 0
    }
}

package org.example.aop.inspection

import com.intellij.codeInspection.AbstractBaseJavaLocalInspectionTool
import com.intellij.codeInspection.LocalQuickFix
import com.intellij.codeInspection.ProblemDescriptor
import com.intellij.codeInspection.ProblemsHolder
import com.intellij.openapi.project.Project
import com.intellij.psi.*
import com.intellij.psi.codeStyle.JavaCodeStyleManager

class AspectNotBeanInspection : AbstractBaseJavaLocalInspectionTool() {

    companion object {
        private const val ASPECT = "org.aspectj.lang.annotation.Aspect"

        private val SPRING_BEAN_ANNOTATIONS = listOf(
            "org.springframework.stereotype.Component",
            "org.springframework.stereotype.Service",
            "org.springframework.stereotype.Repository",
            "org.springframework.stereotype.Controller",
            "org.springframework.web.bind.annotation.RestController"
        )
    }

    override fun buildVisitor(holder: ProblemsHolder, isOnTheFly: Boolean): PsiElementVisitor {
        return object : JavaElementVisitor() {
            override fun visitClass(aClass: PsiClass) {
                if (!aClass.hasAnnotation(ASPECT)) return
                if (SPRING_BEAN_ANNOTATIONS.any { aClass.hasAnnotation(it) }) return

                val aspectAnnotation = aClass.getAnnotation(ASPECT) ?: return

                holder.registerProblem(
                    aspectAnnotation,
                    "@Aspect class '${aClass.name}' is not a Spring Bean — Spring AOP will not apply it",
                    AddComponentFix
                )
            }
        }
    }

    object AddComponentFix : LocalQuickFix {
        override fun getName() = "Add @Component"
        override fun getFamilyName() = "AOP fixes"

        override fun applyFix(project: Project, descriptor: ProblemDescriptor) {
            val annotation = descriptor.psiElement as? PsiAnnotation ?: return
            val psiClass = annotation.parent?.parent as? PsiClass ?: return
            val modifierList = psiClass.modifierList ?: return

            val added = modifierList.addAnnotation("org.springframework.stereotype.Component")
            JavaCodeStyleManager.getInstance(project).shortenClassReferences(added)
        }
    }
}

package org.example.aop.inspection

import com.intellij.codeInspection.AbstractBaseJavaLocalInspectionTool
import com.intellij.codeInspection.LocalQuickFix
import com.intellij.codeInspection.ProblemDescriptor
import com.intellij.codeInspection.ProblemsHolder
import com.intellij.openapi.project.Project
import com.intellij.psi.*
import com.intellij.psi.codeStyle.JavaCodeStyleManager

class AspectNotBeanInspection : AbstractBaseJavaLocalInspectionTool() {

    override fun buildVisitor(holder: ProblemsHolder, isOnTheFly: Boolean): PsiElementVisitor {
        return object : JavaElementVisitor() {
            override fun visitClass(aClass: PsiClass) {
                if (!aClass.hasAnnotation(AopInspectionRules.ASPECT_ANNOTATION)) return
                if (AopInspectionRules.isSpringBeanClass(aClass)) return

                val aspectAnnotation = aClass.getAnnotation(AopInspectionRules.ASPECT_ANNOTATION) ?: return

                holder.registerProblem(
                    aspectAnnotation,
                    "@Aspect class '${aClass.name}' is not a Spring Bean — Spring AOP will not apply it",
                    AddComponentFix
                )
            }
        }
    }

    object AddComponentFix : LocalQuickFix {
        override fun getName() = "Add @Component"
        override fun getFamilyName() = "AOP fixes"

        override fun applyFix(project: Project, descriptor: ProblemDescriptor) {
            val annotation = descriptor.psiElement as? PsiAnnotation ?: return
            val psiClass = annotation.parent?.parent as? PsiClass ?: return
            val modifierList = psiClass.modifierList ?: return

            if (AopInspectionRules.isSpringBeanClass(psiClass)) return

            val added = modifierList.addAnnotation("org.springframework.stereotype.Component")
            JavaCodeStyleManager.getInstance(project).shortenClassReferences(added)
        }
    }
}

package org.example.aop.inspection

import com.intellij.codeInspection.AbstractBaseJavaLocalInspectionTool
import com.intellij.codeInspection.ProblemsHolder
import com.intellij.psi.*

class PointcutSyntaxInspection : AbstractBaseJavaLocalInspectionTool() {

    companion object {
        private val ADVICE_AND_POINTCUT_ANNOTATIONS = setOf(
            "org.aspectj.lang.annotation.Before",
            "org.aspectj.lang.annotation.After",
            "org.aspectj.lang.annotation.Around",
            "org.aspectj.lang.annotation.AfterReturning",
            "org.aspectj.lang.annotation.AfterThrowing",
            "org.aspectj.lang.annotation.Pointcut"
        )

        private val KNOWN_DESIGNATORS = setOf(
            "execution", "within", "this", "target", "args",
            "@target", "@within", "@annotation", "@args", "bean",
            "cflow", "cflowbelow", "initialization", "preinitialization",
            "staticinitialization", "handler", "adviceexecution"
        )
    }

    override fun buildVisitor(holder: ProblemsHolder, isOnTheFly: Boolean): PsiElementVisitor {
        return object : JavaElementVisitor() {
            override fun visitAnnotation(annotation: PsiAnnotation) {
                if (annotation.qualifiedName !in ADVICE_AND_POINTCUT_ANNOTATIONS) return

                val valueLiteral = annotation.findAttributeValue(PsiAnnotation.DEFAULT_REFERENCED_METHOD_NAME)
                    as? PsiLiteralExpression ?: return
                val expression = valueLiteral.value as? String ?: return

                validate(expression.trim(), valueLiteral, holder)
            }
        }
    }

    private fun validate(expression: String, element: PsiElement, holder: ProblemsHolder) {
        if (expression.isEmpty()) {
            holder.registerProblem(element, "Pointcut expression cannot be empty")
            return
        }

        if (!hasBalancedParentheses(expression)) {
            holder.registerProblem(element, "Pointcut expression has unbalanced parentheses")
            return
        }

        // Extract the first token before '(' — could be a designator or a pointcut method reference
        val firstToken = expression
            .trimStart('!')
            .substringBefore("(")
            .trim()
            .split("&&", "||")
            .first()
            .trim()

        if (firstToken.isNotEmpty() && '.' !in firstToken && firstToken !in KNOWN_DESIGNATORS) {
            // Looks like a designator (no dot = not a FQN method ref), but unknown
            holder.registerProblem(element, "Unknown pointcut designator: '$firstToken'")
        }
    }

    private fun hasBalancedParentheses(expr: String): Boolean {
        var depth = 0
        for (ch in expr) {
            when (ch) {
                '(' -> depth++
                ')' -> if (--depth < 0) return false
            }
        }
        return depth == 0
    }
}

package org.example.aop.inspection

import com.intellij.codeInspection.AbstractBaseJavaLocalInspectionTool
import com.intellij.codeInspection.ProblemsHolder
import com.intellij.psi.*

class PointcutSyntaxInspection : AbstractBaseJavaLocalInspectionTool() {

    private val supportedAttributeNames = listOf(
        PsiAnnotation.DEFAULT_REFERENCED_METHOD_NAME,
        "pointcut"
    )

    override fun buildVisitor(holder: ProblemsHolder, isOnTheFly: Boolean): PsiElementVisitor {
        return object : JavaElementVisitor() {
            override fun visitAnnotation(annotation: PsiAnnotation) {
                if (annotation.qualifiedName !in AopInspectionRules.adviceAndPointcutAnnotations) return

                val seenLiterals = mutableSetOf<PsiLiteralExpression>()
                for (attributeName in supportedAttributeNames) {
                    val valueLiteral = annotation.findAttributeValue(attributeName) as? PsiLiteralExpression ?: continue
                    if (!seenLiterals.add(valueLiteral)) continue

                    val expression = valueLiteral.value as? String ?: continue
                    validate(expression, valueLiteral, holder)
                }
            }
        }
    }

    private fun validate(expression: String, element: PsiElement, holder: ProblemsHolder) {
        val error = AopInspectionRules.validatePointcutExpression(expression)
        if (error != null) {
            holder.registerProblem(element, error)
        }
    }
}

package org.example.aop.marker

import com.intellij.codeInsight.daemon.RelatedItemLineMarkerInfo
import com.intellij.codeInsight.daemon.RelatedItemLineMarkerProvider
import com.intellij.codeInsight.navigation.NavigationGutterIconBuilder
import com.intellij.icons.AllIcons
import com.intellij.psi.PsiClass
import com.intellij.psi.PsiElement
import com.intellij.psi.PsiMethod

class AopLineMarkerProvider : RelatedItemLineMarkerProvider() {

    companion object {
        const val ASPECT_ANNOTATION = "org.aspectj.lang.annotation.Aspect"

        val ADVICE_ANNOTATIONS = listOf(
            "org.aspectj.lang.annotation.Before",
            "org.aspectj.lang.annotation.After",
            "org.aspectj.lang.annotation.Around",
            "org.aspectj.lang.annotation.AfterReturning",
            "org.aspectj.lang.annotation.AfterThrowing",
            "org.aspectj.lang.annotation.Pointcut"
        )
    }

    override fun collectNavigationMarkers(
        element: PsiElement,
        result: MutableCollection<in RelatedItemLineMarkerInfo<*>>
    ) {
        when (element) {
            is PsiClass -> markAspectClass(element, result)
            is PsiMethod -> markAdviceMethod(element, result)
        }
    }

    private fun markAspectClass(
        psiClass: PsiClass,
        result: MutableCollection<in RelatedItemLineMarkerInfo<*>>
    ) {
        if (!psiClass.hasAnnotation(ASPECT_ANNOTATION)) return
        val nameIdentifier = psiClass.nameIdentifier ?: return

        val adviceMethods = psiClass.methods.filter { method ->
            ADVICE_ANNOTATIONS.any { ann -> method.hasAnnotation(ann) }
        }
        if (adviceMethods.isEmpty()) return

        result.add(
            NavigationGutterIconBuilder.create(AllIcons.Gutter.ImplementingMethod)
                .setTargets(adviceMethods)
                .setTooltipText("AOP aspect — ${adviceMethods.size} advice method(s)")
                .createLineMarkerInfo(nameIdentifier)
        )
    }

    private fun markAdviceMethod(
        method: PsiMethod,
        result: MutableCollection<in RelatedItemLineMarkerInfo<*>>
    ) {
        val matchedAnnotation = ADVICE_ANNOTATIONS.firstOrNull { method.hasAnnotation(it) } ?: return
        val containingClass = method.containingClass ?: return
        if (!containingClass.hasAnnotation(ASPECT_ANNOTATION)) return
        val nameIdentifier = method.nameIdentifier ?: return

        val shortName = matchedAnnotation.substringAfterLast('.')

        result.add(
            NavigationGutterIconBuilder.create(AllIcons.Gutter.OverridingMethod)
                .setTargets(listOf(containingClass))
                .setTooltipText("@$shortName — aspect: ${containingClass.name}")
                .createLineMarkerInfo(nameIdentifier)
        )
    }
}

package org.example.aop.marker

import com.intellij.codeInsight.daemon.RelatedItemLineMarkerInfo
import com.intellij.codeInsight.daemon.RelatedItemLineMarkerProvider
import com.intellij.codeInsight.navigation.NavigationGutterIconBuilder
import com.intellij.icons.AllIcons
import com.intellij.psi.PsiClass
import com.intellij.psi.PsiElement
import com.intellij.psi.PsiMethod
import org.example.aop.inspection.AopInspectionRules

class AopLineMarkerProvider : RelatedItemLineMarkerProvider() {

    override fun collectNavigationMarkers(
        element: PsiElement,
        result: MutableCollection<in RelatedItemLineMarkerInfo<*>>
    ) {
        when (element) {
            is PsiClass -> markAspectClass(element, result)
            is PsiMethod -> markAdviceMethod(element, result)
        }
    }

    private fun markAspectClass(
        psiClass: PsiClass,
        result: MutableCollection<in RelatedItemLineMarkerInfo<*>>
    ) {
        if (!psiClass.hasAnnotation(AopInspectionRules.ASPECT_ANNOTATION)) return
        val nameIdentifier = psiClass.nameIdentifier ?: return

        val adviceMethods = psiClass.methods.filter { method ->
            AopInspectionRules.adviceAndPointcutAnnotations.any { ann -> method.hasAnnotation(ann) }
        }
        if (adviceMethods.isEmpty()) return

        result.add(
            NavigationGutterIconBuilder.create(AllIcons.Gutter.ImplementingMethod)
                .setTargets(adviceMethods)
                .setTooltipText("AOP aspect — ${adviceMethods.size} advice method(s)")
                .createLineMarkerInfo(nameIdentifier)
        )
    }

    private fun markAdviceMethod(
        method: PsiMethod,
        result: MutableCollection<in RelatedItemLineMarkerInfo<*>>
    ) {
        val matchedAnnotation = AopInspectionRules.adviceAndPointcutAnnotations.firstOrNull { method.hasAnnotation(it) } ?: return
        val containingClass = method.containingClass ?: return
        if (!containingClass.hasAnnotation(AopInspectionRules.ASPECT_ANNOTATION)) return
        val nameIdentifier = method.nameIdentifier ?: return

        val shortName = matchedAnnotation.substringAfterLast('.')

        result.add(
            NavigationGutterIconBuilder.create(AllIcons.Gutter.OverridingMethod)
                .setTargets(listOf(containingClass))
                .setTooltipText("@$shortName — aspect: ${containingClass.name}")
                .createLineMarkerInfo(nameIdentifier)
        )
    }
}

package org.example.aop.completion

import com.intellij.codeInsight.completion.CompletionUtilCore
import kotlin.test.Test
import kotlin.test.assertEquals
import kotlin.test.assertFalse
import kotlin.test.assertTrue

class AopCompletionContextTest {

    @Test
    fun `supports only aop advice annotations`() {
        assertTrue(AopCompletionContext.isSupportedAopAdviceAnnotation("org.aspectj.lang.annotation.Before"))
        assertFalse(AopCompletionContext.isSupportedAopAdviceAnnotation("org.aspectj.lang.annotation.Aspect"))
        assertFalse(AopCompletionContext.isSupportedAopAdviceAnnotation("com.example.Other"))
    }

    @Test
    fun `supports default and named pointcut attributes`() {
        assertTrue(AopCompletionContext.isSupportedPointcutAttribute("value"))
        assertTrue(AopCompletionContext.isSupportedPointcutAttribute("pointcut"))
        assertTrue(AopCompletionContext.isSupportedPointcutAttribute(null))
        assertFalse(AopCompletionContext.isSupportedPointcutAttribute("argNames"))
    }

    @Test
    fun `extracts prefix inside quoted literal`() {
        val tokenText = "\"execution${CompletionUtilCore.DUMMY_IDENTIFIER_TRIMMED}\""

        assertEquals("execution", AopCompletionContext.extractPrefix(tokenText))
    }

    @Test
    fun `extracts prefix when token has no quote`() {
        val tokenText = "within${CompletionUtilCore.DUMMY_IDENTIFIER_TRIMMED}"

        assertEquals("within", AopCompletionContext.extractPrefix(tokenText))
    }

    @Test
    fun `returns empty prefix when dummy marker is absent`() {
        assertEquals("", AopCompletionContext.extractPrefix("\"execution\""))
    }
}

package org.example.aop.inspection

import kotlin.test.Test
import kotlin.test.assertEquals
import kotlin.test.assertNull
import kotlin.test.assertTrue

class AopInspectionRulesTest {

	@Test
	fun `accepts simple valid execution expression`() {
		val error = AopInspectionRules.validatePointcutExpressionDetailed("execution(* com.example..*(..))")

		assertNull(error)
	}

	@Test
	fun `rejects empty expression`() {
		val error = AopInspectionRules.validatePointcutExpressionDetailed("   ")

		assertEquals(AopInspectionRules.PointcutValidationErrorKind.EMPTY_EXPRESSION, error?.kind)
	}

	@Test
	fun `rejects empty negation expression`() {
		val error = AopInspectionRules.validatePointcutExpressionDetailed("!!!")

		assertEquals(AopInspectionRules.PointcutValidationErrorKind.EMPTY_NEGATION, error?.kind)
	}

	@Test
	fun `rejects unbalanced parentheses`() {
		val error = AopInspectionRules.validatePointcutExpressionDetailed("execution(* com.example..*(..)")

		assertEquals(AopInspectionRules.PointcutValidationErrorKind.UNBALANCED_PARENTHESES, error?.kind)
	}

	@Test
	fun `rejects leading logical operator`() {
		val error = AopInspectionRules.validatePointcutExpressionDetailed("&& execution(* *(..))")

		assertEquals(AopInspectionRules.PointcutValidationErrorKind.LEADING_OPERATOR, error?.kind)
	}

	@Test
	fun `rejects trailing logical operator`() {
		val error = AopInspectionRules.validatePointcutExpressionDetailed("execution(* *(..)) ||")

		assertEquals(AopInspectionRules.PointcutValidationErrorKind.TRAILING_OPERATOR, error?.kind)
	}

	@Test
	fun `rejects consecutive logical operators`() {
		val error = AopInspectionRules.validatePointcutExpressionDetailed("execution(* *(..)) && || within(com.example..*)")

		assertEquals(AopInspectionRules.PointcutValidationErrorKind.CONSECUTIVE_LOGICAL_OPERATORS, error?.kind)
	}

	@Test
	fun `rejects missing operator between clauses`() {
		val error = AopInspectionRules.validatePointcutExpressionDetailed("execution(* *(..)) within(com.example..*)")

		assertEquals(AopInspectionRules.PointcutValidationErrorKind.MISSING_OPERATOR_BETWEEN_CLAUSES, error?.kind)
	}

	@Test
	fun `rejects unknown designator`() {
		val error = AopInspectionRules.validatePointcutExpressionDetailed("unknown(* *(..))")

		assertEquals(AopInspectionRules.PointcutValidationErrorKind.UNKNOWN_DESIGNATOR, error?.kind)
		assertTrue(error?.message?.contains("unknown") == true)
	}

	@Test
	fun `allows reference style token with package qualifier`() {
		val error = AopInspectionRules.validatePointcutExpressionDetailed("com.example.MyAspect.somePointcut()")

		assertNull(error)
	}

	@Test
	fun `accepts valid combined designator expression`() {
		val error = AopInspectionRules.validatePointcutExpressionDetailed(
			"execution(* com.example..*(..)) && !within(com.example.internal..*)"
		)

		assertNull(error)
	}

	@Test
	fun `validatePointcutExpression returns message for invalid expression`() {
		val error = AopInspectionRules.validatePointcutExpression("execution(* *(..)) && || within(com.example..*)")

		assertTrue(error?.contains("consecutive logical operators") == true)
	}

	@Test
	fun `detects known Spring bean annotation names`() {
		val annotationNames = setOf(
			"org.aspectj.lang.annotation.Aspect",
			"org.springframework.stereotype.Service"
		)

		assertTrue(AopInspectionRules.hasSpringBeanAnnotation(annotationNames))
	}

	@Test
	fun `aop annotation short names stay aligned with qualified names`() {
		val recomputed = AopInspectionRules.aopAnnotationQualifiedNames
			.map { it.substringAfterLast('.') }
			.toSet()

		assertEquals(recomputed, AopInspectionRules.aopAnnotationShortNames)
	}

	@Test
	fun `completion designators are supported by validator`() {
		val completionDesignators = AopInspectionRules.pointcutCompletionItems.map { it.first }.toSet()

		assertTrue(completionDesignators.all { it in AopInspectionRules.supportedPointcutDesignators })
	}
}
